import './TextField.scss';
import './TextField.stories.scss';

import type { ChangeEvent } from 'react';
import React, { cloneElement, isValidElement, useEffect, useImperativeHandle, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { getBEMClasses } from '../../helpers/get-bem';
import type { TextFieldProps } from './TextField.types';

const [wrapperClassName, wrapperModifier] = getBEMClasses('dsb_text-field-wrapper');
const [inputClassName, inputModifier] = getBEMClasses('dsb_input');
const [, placeholderModifier] = getBEMClasses('dsb_input-placeholder');
const [labelClassName, labelModifier] = getBEMClasses('dsb_input-label');
const [adornmentClassName, adornmentModifier, adornmentBlock] = getBEMClasses('dsb_input-adornment');
const [adornmentItemClassName] = adornmentBlock('item');
const [inputWrapperClassName, inputWrapperModifier] = getBEMClasses('dsb_input-wrapper');

export const TextField = React.forwardRef<HTMLInputElement, TextFieldProps>(
	(
		{
			label,
			size = 'medium',
			startAdornment,
			endAdornment,
			autoComplete = 'off',
			placeholder,
			className,
			id,
			inputId,
			inputClassName: externalInputClassName,
			wrapperClassName: externalWrapperClassName,
			fullWidth = false,
			error = false,
			helperText,
			disabled = false,
			dataTestId = 'TextField',
			helperPosition = 'absolute',
			isClickableAdornment = true,
			onChange,
			isShowCountOfValues,
			counter,
			isFocused,
			maxLength,
			disableMaxLength,
			...props
		},
		ref,
	) => {
		const placeholderValue = placeholder || ' ';
		// дефолтное значение делаем уникальным с помощью рандома
		// если значение будет не уникальным, то при фокусе на лейбле произойдет фокус на первом элементе с подходящим айди
		const [_inputId, setInputId] = useState<string>(inputId);
		const localRef = useRef<HTMLInputElement>(null);
		useImperativeHandle(ref, () => localRef.current);

		useEffect(() => {
			setInputId(inputId || 'dsb_textfield-id-' + Math.random());
		}, [inputId]);

		const showBlock = helperPosition === 'block';
		const showAbs = helperPosition === 'absolute';

		const [valueLength, setValueLength] = useState<number>(0);

		useEffect(() => {
			// Обновляем длину значения при изменении props.value
			if (props.value !== undefined) {
				setValueLength(String(props.value).length);
			}
		}, [props.value]);

		const handleChange = (event: ChangeEvent<HTMLInputElement>) => {
			if (!disabled && onChange) {
				// Если задан maxLength, ограничиваем ввод символов
				if (!disableMaxLength && maxLength !== undefined && event.target.value.length > maxLength) {
					event.target.value = event.target.value.slice(0, maxLength);
				}
				setValueLength(event.target.value.length);
				onChange(event);
			}
		};

		const classedCounter = counter
			? React.cloneElement<any>(counter, {
					className: classNames([
						(counter.props as any).className,
						props.value && inputModifier(size),
						label && inputModifier('labeled'),
						label && size !== 'small' && placeholderModifier('hide'),
					]),
				})
			: null;

		const maxLengthCounter =
			!disableMaxLength && maxLength !== undefined ? (
				<span className="dsb_input-counter" data-testid="TextField-counter">
					{valueLength}/{maxLength}
				</span>
			) : null;

		return (
			<div
				data-testid={dataTestId}
				id={id}
				className={classNames(
					wrapperClassName,
					fullWidth && wrapperModifier('fullwidth'),
					disabled && wrapperModifier('disabled'),
					className,
					externalWrapperClassName,
				)}
			>
				<div
					className={classNames(
						inputWrapperClassName,
						isFocused && inputWrapperModifier('focus'),
						error && inputWrapperModifier('error'),
					)}
				>
					<input
						data-testid={dataTestId + '-input'}
						ref={localRef}
						id={_inputId}
						disabled={disabled}
						placeholder={placeholderValue}
						maxLength={maxLength}
						className={classNames([
							inputClassName,
							error && inputModifier('error'),
							inputModifier(size),
							startAdornment && inputModifier('start-adornment'),
							endAdornment && inputModifier('end-adornment'),
							isFocused && inputModifier('focus'),
							label && inputModifier('labeled'),
							label && size !== 'small' && placeholderModifier('hide'),
							externalInputClassName,
						])}
						aria-invalid={error}
						onChange={handleChange}
						{...props}
						autoComplete={autoComplete}
					/>

					{isShowCountOfValues && classedCounter}

					{label && (
						<label
							data-testid={dataTestId + '-label'}
							htmlFor={_inputId}
							className={classNames(
								labelClassName,
								labelModifier(size),
								startAdornment && labelModifier('start-adornment'),
								endAdornment && labelModifier('end-adornment'),
							)}
						>
							{label}
						</label>
					)}

					{showAbs && (
						<div className="dsb_input-helper-text-absolute-wrapper">
							<sup className="dsb_input-helper-text">{helperText}</sup>
							{!disableMaxLength && maxLength !== undefined && (
								<div className="dsb_input-counter-wrapper">{maxLengthCounter}</div>
							)}
						</div>
					)}

					{startAdornment && (
						<div
							className={classNames(adornmentClassName, adornmentModifier('start'))}
							style={{
								pointerEvents: isClickableAdornment ? 'auto' : 'none',
							}}
							data-testid={dataTestId + '-startAd'}
						>
							{isValidElement(startAdornment)
								? cloneElement<any>(startAdornment, {
										size,
										className: classNames(
											(startAdornment.props as { className?: string }).className,
											adornmentItemClassName,
										),
									})
								: startAdornment}
						</div>
					)}

					{endAdornment && (
						<div
							className={classNames(adornmentClassName, adornmentModifier('end'))}
							style={{
								pointerEvents: isClickableAdornment ? 'auto' : 'none',
							}}
							data-testid={dataTestId + '-endAd'}
						>
							{isValidElement(endAdornment)
								? cloneElement<any>(endAdornment, {
										size,
										className: classNames(
											(endAdornment.props as { className?: string }).className,
											adornmentItemClassName,
										),
									})
								: endAdornment}
						</div>
					)}
				</div>
				{showBlock && (
					<div className="dsb_input-helper-text-block-wrapper">
						<sup className="dsb_input-helper-text">{helperText}</sup>
						{!disableMaxLength && maxLength !== undefined && (
							<div className="dsb_input-counter-wrapper">{maxLengthCounter}</div>
						)}
					</div>
				)}
			</div>
		);
	},
);
